import React, { useState, useEffect } from 'react';
import { materialAPI } from '../services/api';

const MaterialsPage = () => {
  const [materials, setMaterials] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [selectedSubject, setSelectedSubject] = useState('All');

  useEffect(() => {
    fetchMaterials();
  }, []);

  const fetchMaterials = async () => {
    setLoading(true);
    setError('');
    try {
      const res = await materialAPI.getAllMaterials();
      setMaterials(res.data.materials || []);
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to fetch materials');
    } finally {
      setLoading(false);
    }
  };

  const subjects = ['All', ...new Set(materials.map((material) => material.subject))];
  const filteredMaterials =
    selectedSubject === 'All'
      ? materials
      : materials.filter((material) => material.subject === selectedSubject);

  return (
    <div className="container-fluid py-4 min-vh-100">
      <div className="container">
        <div className="portal-page-header">
          <span className="portal-page-kicker">Resources</span>
          <h1 className="portal-page-title">Study Materials</h1>
          <p className="portal-page-subtitle">
            Review uploaded learning resources by subject and access supporting material for
            upcoming sessions.
          </p>
        </div>

        {error && (
          <div className="alert alert-danger alert-dismissible fade show" role="alert">
            {error}
            <button type="button" className="btn-close" onClick={() => setError('')}></button>
          </div>
        )}

        <div className="card portal-section-card shadow-sm mb-4">
          <div className="card-body">
            <div className="portal-filter-bar">
              <div>
                <div className="portal-stat-label">Filter</div>
                <div className="fw-semibold">Browse by subject</div>
              </div>
              <div className="portal-chip-group">
                {subjects.map((subject) => (
                  <button
                    key={subject}
                    className={`btn portal-chip ${
                      selectedSubject === subject ? 'btn-primary' : 'btn-outline-primary'
                    }`}
                    onClick={() => setSelectedSubject(subject)}
                  >
                    {subject}
                  </button>
                ))}
              </div>
            </div>
          </div>
        </div>

        {loading ? (
          <div className="text-center py-5">
            <div className="spinner-border text-primary" role="status">
              <span className="visually-hidden">Loading...</span>
            </div>
          </div>
        ) : filteredMaterials.length === 0 ? (
          <div className="card portal-section-card shadow-sm">
            <div className="portal-empty-state">No materials are available for this subject yet.</div>
          </div>
        ) : (
          <div className="row g-4">
            {filteredMaterials.map((material) => (
              <div key={material._id} className="col-md-6 col-lg-4">
                <div className="card portal-resource-card shadow-sm">
                  <div className="card-body p-4">
                    <div className="portal-stat-label mb-2">{material.subject}</div>
                    <h5 className="fw-bold mb-2">{material.title}</h5>
                    <p className="text-muted mb-4">
                      {material.description || 'No description available.'}
                    </p>
                    <div className="portal-meta-list">
                      <div className="portal-meta-item">
                        <strong>Uploaded by:</strong> {material.staffId?.name || 'Unknown'}
                      </div>
                      <div className="portal-meta-item">
                        <strong>Topic:</strong> {material.topic || 'General'}
                      </div>
                      <div className="portal-meta-item">
                        <strong>Date:</strong>{' '}
                        {new Date(material.uploadedAt).toLocaleDateString()}
                      </div>
                    </div>
                  </div>
                  <div className="card-footer bg-transparent border-0 pt-0 px-4 pb-4">
                    <a
                      href={`http://localhost:5000${material.fileUrl}`}
                      target="_blank"
                      rel="noopener noreferrer"
                      className="btn btn-primary w-100"
                    >
                      {material.fileType === 'link' ? 'Open Resource' : 'Download Material'}
                    </a>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default MaterialsPage;
